1	const PROCESSING_FEE = 5;
2	const COMPONENT_BASE_PREMIUM = 25;
3	const COMPONENT_BLOCK_SIZE = 3;
4	const COMPONENT_BLOCK_PREMIUM = 60;
5	const COMPONENT_INSURANCE_VALUE = 250;
6	const CURSE_SURCHARGE_RATE = 0.5;
7	const FIRST_INSURANCE_RATE = 0.1;
8	const HIGH_ENCHANTMENT_RATE = 0.3;
9	const HIGH_ENCHANTMENT_THRESHOLD = 5;
10	const LOYALTY_DISCOUNT_RATE = 0.2;
11	const LOYALTY_YEARS_THRESHOLD = 2;
12	const FOLLOWUP_DISCOUNT_RATE = 0.15;
13	const DEDUCTIBLE = 100;
14	const CAP_MULTIPLIER = 2;
15	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
16	const HALF_PAYOUT_RATE = 0.5;
17	
18	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
19	  sword: 100,
20	  amulet: 60,
21	  staff: 80,
22	  potion: 40,
23	};
24	
25	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
26	  sword: 1000,
27	  amulet: 600,
28	  staff: 800,
29	  potion: 400,
30	};
31	
32	type Item = {
33	  type: string;
34	  material?: string;
35	  enchantment?: number;
36	  cursed?: boolean;
37	};
38	type Damage = { itemType: string; amount: number };
39	type Incident = { cause: string; damages: Damage[] };
40	type QuoteStep = { op: "quote"; items: Item[] };
41	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
42	type Step = QuoteStep | ClaimStep;
43	type Customer = { yearsWithMHPCO: number; firstQuote?: boolean };
44	type Scenario = { customer: Customer; steps: Step[] };
45	
46	const componentGroupPremium = (count: number): number =>
47	  count === COMPONENT_BLOCK_SIZE
48	    ? COMPONENT_BLOCK_PREMIUM
49	    : count * COMPONENT_BASE_PREMIUM;
50	
51	const isMainItem = ({ type }: Item): boolean => type in BASE_PREMIUM_BY_TYPE;
52	
53	const isHighEnchantment = (item: Item): boolean =>
54	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
55	
56	const qualifiesForFirstInsurance = (item: Item, isSingleItemPolicy: boolean): boolean =>
57	  isSingleItemPolicy && !!item.cursed && !isHighEnchantment(item);
58	
59	const surchargeRates = (item: Item, isSingleItemPolicy: boolean): number[] => [
60	  item.cursed ? CURSE_SURCHARGE_RATE : 0,
61	  isHighEnchantment(item) ? HIGH_ENCHANTMENT_RATE : 0,
62	  qualifiesForFirstInsurance(item, isSingleItemPolicy) ? FIRST_INSURANCE_RATE : 0,
63	];
64	
65	const mainItemPremium = (item: Item, isSingleItemPolicy: boolean): number => {
66	  const base = BASE_PREMIUM_BY_TYPE[item.type];
67	  const totalRate = surchargeRates(item, isSingleItemPolicy).reduce((a, b) => a + b, 1);
68	  return base * totalRate;
69	};
70	
71	const countByType = (items: Item[]): Map<string, number> =>
72	  items.reduce(
73	    (counts, { type }) => counts.set(type, (counts.get(type) ?? 0) + 1),
74	    new Map<string, number>(),
75	  );
76	
77	const sumComponentPremiums = (components: Item[]): number =>
78	  [...countByType(components).values()]
79	    .reduce((sum, count) => sum + componentGroupPremium(count), 0);
80	
81	const partitionItems = (items: Item[]): { mains: Item[]; components: Item[] } =>
82	  items.reduce<{ mains: Item[]; components: Item[] }>(
83	    (acc, item) => {
84	      (isMainItem(item) ? acc.mains : acc.components).push(item);
85	      return acc;
86	    },
87	    { mains: [], components: [] },
88	  );
89	
90	const sumItemPremiums = (items: Item[], policyRate: number): number => {
91	  const { mains, components } = partitionItems(items);
92	  const isSingleItemPolicy = items.length === 1;
93	  const { baseSum, premiumSum } = mains.reduce(
94	    (acc, item) => ({
95	      baseSum: acc.baseSum + BASE_PREMIUM_BY_TYPE[item.type],
96	      premiumSum: acc.premiumSum + mainItemPremium(item, isSingleItemPolicy),
97	    }),
98	    { baseSum: 0, premiumSum: 0 },
99	  );
100	  const componentsSum = sumComponentPremiums(components);
101	  return premiumSum + componentsSum + (baseSum + componentsSum) * policyRate;
102	};
103	
104	const customerRateAdjustments = (customer: Customer, isFollowUp: boolean): number[] => [
105	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? -LOYALTY_DISCOUNT_RATE : 0,
106	  customer.firstQuote ? FIRST_INSURANCE_RATE : 0,
107	  isFollowUp ? -FOLLOWUP_DISCOUNT_RATE : 0,
108	];
109	
110	const policyWideRate = (customer: Customer, isFollowUp: boolean): number =>
111	  customerRateAdjustments(customer, isFollowUp).reduce((sum, rate) => sum + rate, 0);
112	
113	const ceilInFavor = (value: number): number => Math.ceil(Number(value.toFixed(6)));
114	
115	const quotePremiumFor = (step: QuoteStep, customer: Customer, isFollowUp: boolean): { premium: number } => ({
116	  premium: ceilInFavor(sumItemPremiums(step.items, policyWideRate(customer, isFollowUp)) + PROCESSING_FEE),
117	});
118	
119	const itemInsuranceValue = (item: Item): number =>
120	  isMainItem(item) ? INSURANCE_VALUE_BY_TYPE[item.type] : COMPONENT_INSURANCE_VALUE;
121	
122	const policyInsuranceSum = (items: Item[]): number =>
123	  items.reduce((sum, item) => sum + itemInsuranceValue(item), 0);
124	
125	const findPolicyItem = (policyItems: Item[], itemType: string): Item | undefined =>
126	  policyItems.find((item) => item.type === itemType);
127	
128	const halvesPayout = (item: Item | undefined): boolean =>
129	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD;
130	
131	const damagePayout = (damage: Damage, policyItems: Item[]): number => {
132	  const policyItem = findPolicyItem(policyItems, damage.itemType);
133	  const reimbursed = halvesPayout(policyItem) ? damage.amount * HALF_PAYOUT_RATE : damage.amount;
134	  return Math.max(0, reimbursed - DEDUCTIBLE);
135	};
136	
137	const claimResult = (
138	  step: ClaimStep,
139	  policyItems: Item[],
140	  remainingCap: number,
141	): { payout: number; remainingCap: number } => {
142	  const rawPayout = step.incident.damages.reduce((sum, d) => sum + damagePayout(d, policyItems), 0);
143	  const payout = Math.floor(Math.min(rawPayout, remainingCap));
144	  return { payout, remainingCap: remainingCap - payout };
145	};
146	
147	const policyItemsAt = (scenario: Scenario, policyIndex: number): Item[] =>
148	  (scenario.steps[policyIndex] as QuoteStep).items;
149	
150	const policyCap = (scenario: Scenario, policyIndex: number): number =>
151	  policyInsuranceSum(policyItemsAt(scenario, policyIndex)) * CAP_MULTIPLIER;
152	
153	type RunState = { results: unknown[]; remainingCaps: Map<number, number> };
154	
155	const runStep = (state: RunState, step: Step, index: number, scenario: Scenario): RunState => {
156	  if (step.op === "quote") {
157	    state.results.push(quotePremiumFor(step, scenario.customer, index > 0));
158	    return state;
159	  }
160	  const remainingCap = state.remainingCaps.get(step.policy) ?? policyCap(scenario, step.policy);
161	  const result = claimResult(step, policyItemsAt(scenario, step.policy), remainingCap);
162	  state.remainingCaps.set(step.policy, result.remainingCap);
163	  state.results.push(result);
164	  return state;
165	};
166	
167	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
168	  const initial: RunState = { results: [], remainingCaps: new Map() };
169	  const final = scenario.steps.reduce(
170	    (state, step, i) => runStep(state, step, i, scenario),
171	    initial,
172	  );
173	  return { results: final.results };
174	};
